def _snowflake_listing_to_nested(
    snowflake_listing: SnowflakeListing,
) -> SnowflakeListingNested:
    """Convert flat SnowflakeListing to nested format."""
    attrs = SnowflakeListingAttributes()
    _populate_snowflake_listing_attrs(attrs, snowflake_listing)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        snowflake_listing,
        _SNOWFLAKE_LISTING_REL_FIELDS,
        SnowflakeListingRelationshipAttributes,
    )
    return SnowflakeListingNested(
        guid=snowflake_listing.guid,
        type_name=snowflake_listing.type_name,
        status=snowflake_listing.status,
        version=snowflake_listing.version,
        create_time=snowflake_listing.create_time,
        update_time=snowflake_listing.update_time,
        created_by=snowflake_listing.created_by,
        updated_by=snowflake_listing.updated_by,
        classifications=snowflake_listing.classifications,
        classification_names=snowflake_listing.classification_names,
        meanings=snowflake_listing.meanings,
        labels=snowflake_listing.labels,
        business_attributes=snowflake_listing.business_attributes,
        custom_attributes=snowflake_listing.custom_attributes,
        pending_tasks=snowflake_listing.pending_tasks,
        proxy=snowflake_listing.proxy,
        is_incomplete=snowflake_listing.is_incomplete,
        provenance_type=snowflake_listing.provenance_type,
        home_id=snowflake_listing.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _snowflake_listing_from_nested(nested: SnowflakeListingNested) -> SnowflakeListing:
    """Convert nested format to flat SnowflakeListing."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else SnowflakeListingAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _SNOWFLAKE_LISTING_REL_FIELDS,
        SnowflakeListingRelationshipAttributes,
    )
    return SnowflakeListing(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_snowflake_listing_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _snowflake_listing_to_nested_bytes(
    snowflake_listing: SnowflakeListing, serde: Serde
) -> bytes:
    """Convert flat SnowflakeListing to nested JSON bytes."""
    return serde.encode(_snowflake_listing_to_nested(snowflake_listing))


def _snowflake_listing_from_nested_bytes(data: bytes, serde: Serde) -> SnowflakeListing:
    """Convert nested JSON bytes to flat SnowflakeListing."""
    nested = serde.decode(data, SnowflakeListingNested)
    return _snowflake_listing_from_nested(nested)


